// © 2026 Adobe. All rights reserved. See /COPYRIGHT for details
import type { Entity } from '@adobe/data/ecs';
import { TimeUtils, type TimelineDuration } from '../../../../flick-time/flick-time.js';
import type { CoreStateStore } from '../core-state-plugin.js';
import { writeGaplessInsertPreviewDuration } from '../ecs-boundary/resource-writes.js';
import { TemporalUtils, TrackUtils } from '../foundation/index.js';

/**
 * Compute and write the live gapless insert preview index for cross-track drag.
 * Not undo-tracked. Set destinationTrackId to null to clear the preview.
 *
 * Uses midpoint comparison (same algorithm as dragSelectedTrackItems gapless reorder)
 * to determine where the dragged clip would land if dropped at `dropOffset`.
 *
 * `excludeIds`: items currently being dragged that have already been
 * mid-drag-reparented onto the destination track (FFP-90492). Including
 * them in the sibling list shifts the insert index by N (selection size),
 * landing the commit N slots to the right of the cursor.
 */
export const previewCrossTrackGaplessInsert = (
  t: CoreStateStore,
  {
    destinationTrackId,
    dropOffset,
    draggedItemDuration,
    excludeIds,
  }: {
    destinationTrackId: Entity | null;
    dropOffset: TimelineDuration;
    draggedItemDuration: TimelineDuration;
    excludeIds?: ReadonlyArray<Entity>;
  }
) => {
  if (destinationTrackId === null) {
    t.resources.gaplessInsertPreviewIndex = null;
    t.resources.gaplessInsertPreviewTrackId = null;
    writeGaplessInsertPreviewDuration(t, null);
    return;
  }

  const excludeSet = excludeIds && excludeIds.length > 0 ? new Set<Entity>(excludeIds) : null;
  const siblings = t.select(t.archetypes.TrackItem.components, { where: { parentTrack: destinationTrackId } });
  const items = siblings
    .filter(id => excludeSet === null || !excludeSet.has(id))
    .map(id => ({
      id,
      offset: TimeUtils.timelineDuration(t.get(id, 'explicitTimeOffset') ?? 0),
      duration: TemporalUtils.computeItemTimelineDuration(t, id),
    }))
    .sort((a, b) => TimeUtils.compare(a.offset, b.offset));

  const targetMidpoint = TimeUtils.add(TimeUtils.durationToTime(dropOffset), TimeUtils.divide(draggedItemDuration, 2));
  const insertIdx = TrackUtils.findGaplessInsertIndex(items, targetMidpoint);
  // TEMP DEBUG FFP-90492 — remove before merge
  // eslint-disable-next-line no-console
  console.warn('[FFP-90492-preview-debug2] insertIdx=', insertIdx, 'items.length=', items.length, 'dropOffset.flick=', JSON.stringify(dropOffset), 'duration.flick=', JSON.stringify(draggedItemDuration), 'targetMidpoint=', JSON.stringify(targetMidpoint));

  t.resources.gaplessInsertPreviewIndex = insertIdx;
  t.resources.gaplessInsertPreviewTrackId = destinationTrackId;
  writeGaplessInsertPreviewDuration(t, draggedItemDuration);
};

