1	// © 2026 Adobe. All rights reserved. See /COPYRIGHT for details.
2	//
3	// Grouped cross-track drag action (Phase 4d).
4	//
5	// Extracted verbatim from `actions/drag-actions.ts`. The geometry helpers
6	// (computeLeadingEdgeDrop + computePerItemDropOffsets) already de-duplicate
7	// the cross-track and new-track commit layouts that Phase 4d set out to
8	// simplify; what remained after Phase 3 was a pure relocation.
9	import { Entity } from '@adobe/data/ecs';
10	import type { DragState } from '../../../../../../../../elements/hooks/use-drag-observe.js';
11	import { TimeUtils, type TimelineDuration, type TimelineTime } from '../../../../../flick-time/flick-time.js';
12	import { TIMELINE_DURATION_ZERO } from '../../../../../flick-time/zero-constants.js';
13	import { globalSnapThresholdInPx } from '../../../../../snap/snap-targets.js';
14	import { TrackUtils } from '../../foundation/index.js';
15	import type { BaseDb } from '../shared/base-db.js';
16	import { collectDragSnapTargets } from '../shared/collect-drag-snap-targets.js';
17	import {
18	  clearDestinationPreview,
19	  paintDestinationDropZone,
20	  paintSourceDropZone,
21	  pruneStaleDestinationDropZone,
22	} from '../shared/drag-drop-zones.js';
23	import {
24	  computeClickOffsetWithinGroup,
25	  computeExcursionReturnDelta,
26	  computeGroupDuration,
27	  computeItemDurationFromDb,
28	  computeLeadingEdgeDrop,
29	  computePerItemDropOffsets,
30	  isWholeTrackAdjacentMoveNoop,
31	  snapshotOffsets,
32	  sortByOriginalOffset,
33	} from '../shared/drag-geometry.js';
34	import { beginDragSession, clearCrossTrackDragVisualState, finalizeFreeformOverlapIfNeeded } from '../shared/drag-session.js';
35	import { computeDropSnap } from './frame-state-machine/compute-drop-snap.js';
36	import { computeSameTrackSnap } from './frame-state-machine/compute-same-track-snap.js';
37	
38	/**
39	 * Move multiple selected track items from the same source track (cross-track or same-track).
40	 *
41	 * Parallel to crossTrackMoveItem but handles a group of selected clips that all share
42	 * the same source track. The clicked item is `clickedItemId`; the full selected group is
43	 * discovered at drag start by reading selectedByUsers from ECS.
44	 *
45	 * Same-track gapless: calls reorderGaplessGroupAbsolute per-frame using a frozen
46	 * leadingItemOriginalOffset (smallest offset in the group at drag start).
47	 *
48	 * Cross-track: calls previewCrossTrackGaplessInsert with totalGroupDuration per-frame;
49	 * on drop calls crossTrackMoveItems with per-item offsets computed from the group layout.
50	 *
51	 * Snap: uses the passed selectedItemIds set (leading item as snap reference), mirroring
52	 * crossTrackMoveItem's direct-parameter approach.
53	 *
54	 * Playback: pauses on drag start (AC1); does NOT resume on drop.
55	 */
56	export const crossTrackMoveItems = async (
57	  db: BaseDb,
58	  {
59	    clickedItemId,
60	    sourceTrackId,
61	    drag,
62	    selectedItemIds,
63	    clickXOffsetWithinClickedItem,
64	  }: {
65	    clickedItemId: Entity;
66	    sourceTrackId: Entity;
