  // Media-kind guard. Mirrors `cross-track-move-items.ts:50`. A mismatched
  // reparent can never land — refuse early so the item stays on the source.
  const sourceTrackKind = t.get(currentParent, 'trackKind');
  const destTrackKind = t.get(destinationTrackId, 'trackKind');
  if (sourceTrackKind !== destTrackKind) return;

  // Assign `t.undoable` AFTER every early-return. Setting it before an
  // early-return is semantically a no-op at the undo-stack level (no writes
  // follow → no frame lands; verified by the no-observable-mutation probe
  // notes in `reparent-track-item-live.test.ts`). This ordering is a style
  // convention only: authorize a frame at the point we commit to writing one.
  t.undoable = { coalesce: coalesceMarker };

  // 1. Point the item at the destination.
  t.update(itemId, { parentTrack: destinationTrackId });

  // 2. Strip the item from source's children (idempotent — remove returns
  // a new filtered array; no-op write is skipped inside writeTrackChildren).
  {
    const srcChildren = (t.get(currentParent, 'children') ?? []) as readonly Entity[];
    const srcNext = TrackChildrenUtils.remove(srcChildren, itemId);
    if (srcNext !== srcChildren) writeTrackChildren(t, currentParent, srcNext);
  }

  // 3. Place into destination's children. Gapless destinations respect the
  // cursor-chosen insert index (children order == visual order invariant).
  // Freeform destinations use bring-to-front for last-wins z-order.
  {
    const destChildren = (t.get(destinationTrackId, 'children') ?? []) as readonly Entity[];
    const destEditingMode = t.get(destinationTrackId, 'editingMode');
    const destNext =
      destEditingMode === 'gapless' && destinationInsertIndex !== undefined
        ? TrackChildrenUtils.insertAt(destChildren, itemId, destinationInsertIndex)
        : TrackChildrenUtils.bringToFront(destChildren, itemId);
    writeTrackChildren(t, destinationTrackId, destNext);
