input.new_string:
const currentParent = t.get(itemId, 'parentTrack');
if (currentParent === undefined) return;
// Same-parent path: when the item is already on destination, an explicit
// `destinationInsertIndex` means the caller wants to REPOSITION the item
// within the destination row (cursor moved horizontally on a gapless row
// mid-drag). Re-emit children with the item moved to the requested slot.
// FFP-90492 follow-up #2: without this branch, the dropzone block stays
// frozen at the slot where the item first crossed onto the destination,
// even as the cursor moves further across the destination row.
if (currentParent === destinationTrackId) {
  if (destinationInsertIndex === undefined) return;
  const destEditingMode = t.get(destinationTrackId, 'editingMode');
  if (destEditingMode !== 'gapless') return;
  const destChildren = (t.get(destinationTrackId, 'children') ?? []) as readonly Entity[];
  const currentIndex = destChildren.indexOf(itemId);
  if (currentIndex < 0) return;
  // No-op when the item is already at the requested slot. The reposition
  // is observable: clamp the requested index against the array length-1
  // so insertAt never appends past the end (TrackChildrenUtils.insertAt
  // accepts up to length, but for an in-place move we never grow).
  const target = Math.max(0, Math.min(destinationInsertIndex, destChildren.length - 1));
  if (target === currentIndex) return;
  t.undoable = { coalesce: coalesceMarker };
  const without = TrackChildrenUtils.remove(destChildren, itemId);
  const reordered = TrackChildrenUtils.insertAt(without, itemId, target);
  writeTrackChildren(t, destinationTrackId, reordered);
  return;
}

