// © 2026 Adobe. All rights reserved. See /COPYRIGHT for details
import type { Entity } from '@adobe/data/ecs';
import type { CoreStateStore } from '../core-state-plugin.js';
import { writeTrackChildren } from '../ecs-boundary/component-writes.js';
import { TrackChildrenUtils } from '../foundation/index.js';

/**
 * Per-frame mid-drag reparent of a single track item to a different track.
 *
 * Hz parity: this is the narrow-MVP equivalent of Hz's ephemeral
 * `SceneGraph.moveChild(trackItem, { parent: destinationTrack })` inside a
 * per-frame multi-frame transaction chain keyed by `mergeId`
 * (`platform/authoring/timeline-authoring/src/singletons/ReparentHelper.ts`
 * and `platform/authoring/document-infra/transactions/src/TransactionManager.ts`).
 * FFP has no `ephemeral: true` flag and no `cancelMultiframeTransaction`
 * (deferred to Phase 4 / Variant A-i); instead, every mid-drag call reuses the
 * gesture's `coalesceMarker` so all per-frame frames merge into a single undo
 * step and match Hz's one-undo-per-completed-drag invariant.
 *
 * Writes (minimal set):
 *   - `parentTrack` → `destinationTrackId` on the item.
 *   - Source track's `children` with `itemId` removed (no-op if already
 *     absent — TrackChildrenUtils.remove is idempotent).
 *   - Destination track's `children` with `itemId` brought to front (no-op
 *     on an already-present-and-last id — TrackChildrenUtils.bringToFront
 *     dedupes and appends).
 *
 * `writeTrackChildren` is idempotent at the ECS-boundary sink: when the
 * proposed array is element-equal to the current one, it returns `false` and
 * skips the `t.update` call — no spurious undo frame for a no-op reparent.
 *
 * Guards:
 *   - Early return if `itemId` already has `parentTrack === destinationTrackId`
 *     (caller also guards; this is belt-and-suspenders).
 *   - Media-kind guard IDENTICAL to `cross-track-move-items.ts:50` — refuse
 *     when `sourceTrackKind !== destTrackKind`. Prevents a per-frame reparent
 *     from ever planting an audio item on a video row; the rejected-drag
 *     visual path is handled by the caller re-dispatching this transaction
 *     with the source track as the destination at reject time.
 *
 * Coalesce contract: callers always pass a `coalesceMarker` minted once per
 * gesture via `nextTransientSessionMarker()`. Same marker → merge; distinct
 * markers → separate frames (Hz parity). See
 * `.claude/rules/squirrel/transient-session.md` §2 and Test B in
 * `drag-undo-coalesce.test.ts`.
 *
 * NOT responsible for:
 *   - Updating `explicitTimeOffset` on the reparented item. Drop-commit
 *     (`crossTrackMoveItems`) writes the final offset; during the drag the
 *     item's timeline-space position is visually covered by
 *     `isBeingDragged`'s grey+blue block at the clone's cursor-driven location.
 *   - Gapless-destination sibling reorder. Phase 3 replaces the existing
 *     `previewCrossTrackGaplessInsert` resource with a real ECS reorder per
 *     frame. Phase 2 keeps the existing preview semantics for siblings.
 *   - Freeform overlap resolution. Runs only at drop-commit (and must run
 *     after the final reparent lands, which it does — commit reads
 *     `parentTrack` which is already destination).
 */
export const reparentTrackItemLive = (
  t: CoreStateStore,
  {
    itemId,
    destinationTrackId,
    destinationInsertIndex,
    coalesceMarker,
  }: {
    itemId: Entity;
    destinationTrackId: Entity;
    /**
     * Insert position within the destination track's `children` array. Required
     * for gapless destinations: the render layer consults `children` order
     * directly, so the mid-drag reparent must land the item at the cursor-
     * chosen index (caller computes via `findGaplessInsertIndex`). Ignored
     * for freeform destinations, which use bring-to-front semantics.
     */
    destinationInsertIndex?: number;
    /**
     * Per-gesture marker minted at drag start via
     * `nextTransientSessionMarker()`. Every mid-drag reparent in the same
     * gesture shares this marker so they collapse into a single undo frame.
     */
    coalesceMarker: number;
  }
) => {
  const currentParent = t.get(itemId, 'parentTrack');
  if (currentParent === undefined) return;
  // Idempotency: destination === current parent is a no-op. Caller already
  // guards; this is belt-and-suspenders for direct-test and future refactors.
  if (currentParent === destinationTrackId) return;

  // Media-kind guard. Mirrors `cross-track-move-items.ts:50`. A mismatched
  // reparent can never land — refuse early so the item stays on the source.
  const sourceTrackKind = t.get(currentParent, 'trackKind');
  const destTrackKind = t.get(destinationTrackId, 'trackKind');
  if (sourceTrackKind !== destTrackKind) return;

  // Assign `t.undoable` AFTER every early-return. Setting it before an
  // early-return is semantically a no-op at the undo-stack level (no writes
  // follow → no frame lands; verified by the no-observable-mutation probe
  // notes in `reparent-track-item-live.test.ts`). This ordering is a style
  // convention only: authorize a frame at the point we commit to writing one.
  t.undoable = { coalesce: coalesceMarker };

  // 1. Point the item at the destination.
  t.update(itemId, { parentTrack: destinationTrackId });

  // 2. Strip the item from source's children (idempotent — remove returns
  // a new filtered array; no-op write is skipped inside writeTrackChildren).
  {
    const srcChildren = (t.get(currentParent, 'children') ?? []) as readonly Entity[];
    const srcNext = TrackChildrenUtils.remove(srcChildren, itemId);
    if (srcNext !== srcChildren) writeTrackChildren(t, currentParent, srcNext);
  }

  // 3. Place into destination's children. Gapless destinations respect the
  // cursor-chosen insert index (children order == visual order invariant).
  // Freeform destinations use bring-to-front for last-wins z-order.
  {
    const destChildren = (t.get(destinationTrackId, 'children') ?? []) as readonly Entity[];
    const destEditingMode = t.get(destinationTrackId, 'editingMode');
    const destNext =
      destEditingMode === 'gapless' && destinationInsertIndex !== undefined
        ? TrackChildrenUtils.insertAt(destChildren, itemId, destinationInsertIndex)
        : TrackChildrenUtils.bringToFront(destChildren, itemId);
    writeTrackChildren(t, destinationTrackId, destNext);
  }
};

