// ──────────────────────────────────────────────────────────────────────────
// FFP-90492 follow-up #2 — same-parent reorder path.
// When the item is ALREADY on `destinationTrackId` and an explicit
// `destinationInsertIndex` is provided, the transaction repositions the
// item within the destination's children. Without this branch, the
// dropzone block stays frozen at the slot where the item first crossed
// onto the destination, even as the cursor moves further across the row.
// ──────────────────────────────────────────────────────────────────────────

describe('reparentTrackItemLive — same-parent reorder (FFP-90492 follow-up #2)', () => {
  test('item already on destination + explicit insert index → repositions within children', () => {
    const db = Database.create(transactionsPlugin);
    const dst = db.transactions.testMakeTrack({ editingMode: 'gapless', trackKind: 'video' });
    const a = db.transactions.testMakeItem({ parentTrack: dst, offset: 0, trimOut: Math.round(flicksPerSecond * 2) });
    const b = db.transactions.testMakeItem({ parentTrack: dst, offset: Math.round(flicksPerSecond * 2), trimOut: Math.round(flicksPerSecond * 2) });
    const c = db.transactions.testMakeItem({ parentTrack: dst, offset: Math.round(flicksPerSecond * 4), trimOut: Math.round(flicksPerSecond * 2) });

    // Initial children: [a, b, c]. Move `a` from index 0 to index 2.
    db.transactions.reparentTrackItemLive({
      itemId: a,
      destinationTrackId: dst,
      destinationInsertIndex: 2,
      coalesceMarker: 100,
    });

    assert({
      given: 'item a already on dst at index 0, requested insert index 2',
      should: 'children reorder to [b, c, a]',
      actual: [...(db.get(dst, 'children') ?? [])],
      expected: [b, c, a],
    });
  });

  test('item already at requested index → no-op (no undo frame)', () => {
    const db = Database.create(transactionsPlugin);
    const undoRedo = createUndoRedoService();
    db.subscribe(undoRedo);
    const dst = db.transactions.testMakeTrack({ editingMode: 'gapless', trackKind: 'video' });
    const a = db.transactions.testMakeItem({ parentTrack: dst, offset: 0, trimOut: Math.round(flicksPerSecond * 2) });
    db.transactions.testMakeItem({ parentTrack: dst, offset: Math.round(flicksPerSecond * 2), trimOut: Math.round(flicksPerSecond * 2) });
    const undoCountBefore = undoRedo.undoStack.length;

    db.transactions.reparentTrackItemLive({
      itemId: a,
      destinationTrackId: dst,
      destinationInsertIndex: 0,
      coalesceMarker: 100,
    });

    assert({
      given: 'item a already at children[0], requested insert index 0',
      should: 'no undo frame written',
      actual: undoRedo.undoStack.length,
      expected: undoCountBefore,
    });
  });

  test('item on dst + missing insert index → no-op (preserves prior idempotent contract)', () => {
    const db = Database.create(transactionsPlugin);
    const dst = db.transactions.testMakeTrack({ editingMode: 'gapless', trackKind: 'video' });
    const a = db.transactions.testMakeItem({ parentTrack: dst, offset: 0, trimOut: Math.round(flicksPerSecond * 2) });
    const b = db.transactions.testMakeItem({ parentTrack: dst, offset: Math.round(flicksPerSecond * 2), trimOut: Math.round(flicksPerSecond * 2) });

    db.transactions.reparentTrackItemLive({
      itemId: a,
      destinationTrackId: dst,
      // destinationInsertIndex omitted
      coalesceMarker: 100,
    });

    assert({
      given: 'item a already on dst, no insert index provided',
      should: 'children unchanged (idempotent same-parent no-op)',
      actual: [...(db.get(dst, 'children') ?? [])],
      expected: [a, b],
    });
  });

  test('freeform destination + insert index → no-op (reorder is gapless-only)', () => {
    const db = Database.create(transactionsPlugin);
    const dst = db.transactions.testMakeTrack({ editingMode: 'freeform', trackKind: 'video' });
    const a = db.transactions.testMakeItem({ parentTrack: dst, offset: 0, trimOut: Math.round(flicksPerSecond * 2) });
    const b = db.transactions.testMakeItem({ parentTrack: dst, offset: Math.round(flicksPerSecond * 5), trimOut: Math.round(flicksPerSecond * 2) });

    db.transactions.reparentTrackItemLive({
      itemId: a,
      destinationTrackId: dst,
      destinationInsertIndex: 1,
      coalesceMarker: 100,
    });

    assert({
      given: 'freeform dst, item a on dst, insert index provided',
      should: 'children unchanged (freeform uses bring-to-front; reorder path skipped)',
      actual: [...(db.get(dst, 'children') ?? [])],
      expected: [a, b],
    });
  });

  test('out-of-range insert index → clamped to length-1', () => {
    const db = Database.create(transactionsPlugin);
    const dst = db.transactions.testMakeTrack({ editingMode: 'gapless', trackKind: 'video' });
    const a = db.transactions.testMakeItem({ parentTrack: dst, offset: 0, trimOut: Math.round(flicksPerSecond * 2) });
    const b = db.transactions.testMakeItem({ parentTrack: dst, offset: Math.round(flicksPerSecond * 2), trimOut: Math.round(flicksPerSecond * 2) });
    const c = db.transactions.testMakeItem({ parentTrack: dst, offset: Math.round(flicksPerSecond * 4), trimOut: Math.round(flicksPerSecond * 2) });

    // Request index 99 — well past length 3. Clamps to length-1=2.
    db.transactions.reparentTrackItemLive({
      itemId: a,
      destinationTrackId: dst,
      destinationInsertIndex: 99,
      coalesceMarker: 100,
    });

    assert({
      given: 'out-of-range insert index 99 in 3-item children',
      should: 'clamp to 2 → children reorder to [b, c, a]',
      actual: [...(db.get(dst, 'children') ?? [])],
      expected: [b, c, a],
    });
  });
});

