// Record a multi-position cursor traversal across the destination row,
// dwelling at each target so the video shows the dropzone tracking.
import { chromium } from 'playwright';
import * as fs from 'node:fs';
import * as path from 'node:path';

const OUT_DIR = '/tmp/ffp-90492-bug2-recordings';
const PORT = parseInt(process.env.PORT || '3102', 10);
const LABEL = process.env.LABEL || 'TRAVERSAL';
const VIDEO_DIR = path.join(OUT_DIR, `video-${LABEL}`);
fs.mkdirSync(VIDEO_DIR, { recursive: true });

(async () => {
  const browser = await chromium.launch({ headless: true, args: ['--ignore-certificate-errors'] });
  const ctx = await browser.newContext({
    ignoreHTTPSErrors: true,
    viewport: { width: 1600, height: 900 },
    recordVideo: { dir: VIDEO_DIR, size: { width: 1600, height: 900 } },
  });
  const page = await ctx.newPage();

  await page.goto(`https://localhost.adobe.com:${PORT}/?config=squirrel&e2eAssets=local&disableCloudSync=true&disableUnavAnalytics=true`, { waitUntil: 'domcontentloaded' });
  await page.waitForFunction(() => {
    const w = (r, sel) => { const o = []; const f = (x) => { if (!x) return; if (x.querySelectorAll) for (const m of x.querySelectorAll(sel)) o.push(m); if (x.querySelectorAll) for (const el of x.querySelectorAll('*')) if (el.shadowRoot) f(el.shadowRoot); }; f(r); return o; };
    return w(document, '[data-testid="track-placeholder"]').length >= 2;
  }, null, { timeout: 60000 });
  await page.waitForTimeout(2500);

  const pre = await page.evaluate(() => {
    function walk(root, sel) { const out = []; const f = (r) => { if (!r) return; if (r.querySelectorAll) for (const m of r.querySelectorAll(sel)) out.push(m); if (r.querySelectorAll) for (const el of r.querySelectorAll('*')) if (el.shadowRoot) f(el.shadowRoot); }; f(root); return out; }
    function rect(el) { const r = el.getBoundingClientRect(); return { x: Math.round(r.x), y: Math.round(r.y), w: Math.round(r.width), h: Math.round(r.height) }; }
    const tracks = walk(document, '[data-testid="track-placeholder"]');
    return tracks.map((t, i) => ({ ti: i, mode: t.getAttribute('data-track-mode'), rect: rect(t), items: walk(t, '[data-testid^="trackItem-"]').slice(0, 8).map((s) => ({ id: s.getAttribute('data-entity-id'), rect: rect(s) })) }));
  });
  const sourceTrack = pre.find((t) => t.mode === 'freeform' && t.items.length >= 2);
  const destTrack = pre.find((t) => t.ti !== sourceTrack.ti && t.mode === 'gapless');
  const item1 = sourceTrack.items[0];
  const item2 = sourceTrack.items[1];

  await page.mouse.click(item1.rect.x + item1.rect.w / 2, item1.rect.y + item1.rect.h / 2);
  await page.waitForTimeout(300);
  await page.keyboard.down('Meta');
  await page.mouse.click(item2.rect.x + item2.rect.w / 2, item2.rect.y + item2.rect.h / 2);
  await page.keyboard.up('Meta');
  await page.waitForTimeout(300);

  const fromX = Math.round(item1.rect.x + item1.rect.w / 2);
  const fromY = Math.round(item1.rect.y + item1.rect.h / 2);
  const destY = Math.round(destTrack.rect.y + destTrack.rect.h / 2);

  await page.mouse.move(fromX, fromY, { steps: 8 });
  await page.waitForTimeout(200);
  await page.mouse.down();
  await page.waitForTimeout(150);
  await page.mouse.move(fromX + 8, fromY, { steps: 4 });
  await page.waitForTimeout(150);

  // Move to dest row, then traverse multiple positions left-to-right with dwells
  const traversal = [400, 700, 1000, 1300, 1000, 700, 400, 700, 1000, 1300];
  for (const px of traversal) {
    await page.mouse.move(px, destY, { steps: 25 });
    await page.waitForTimeout(700);
  }
  await page.mouse.up();
  await page.waitForTimeout(800);

  await page.close();
  await ctx.close();
  await browser.close();

  const videoFiles = fs.readdirSync(VIDEO_DIR).filter((f) => f.endsWith('.webm'));
  if (videoFiles.length > 0) {
    const src = path.join(VIDEO_DIR, videoFiles[0]);
    const dst = path.join(OUT_DIR, `${LABEL}.webm`);
    fs.renameSync(src, dst);
    console.log(`video → ${dst}`);
  }
})().catch((e) => { console.error(e); process.exit(1); });

